bulkOperationsFirstAndLast.query:
#graphql
  query BulkOperationsFirstAndLastValidation {
    bulkOperations(first: 1, last: 1) {
      nodes {
        id
      }
    }
  }

bulkOperationsInvalidSearch.query:
#graphql
  query BulkOperationsInvalidSearchValidation {
    bulkOperations(first: 1, query: "created_at:>=not-a-date") {
      nodes {
        id
      }
    }
  }

bulkOperationCancelMissingId.query:
#graphql
  mutation BulkOperationCancelMissingIdValidation {
    bulkOperationCancel {
      userErrors {
        field
        message
      }
    }
  }

bulkOperationCancelUnknownId.query:
#graphql
  mutation BulkOperationCancelCapture($id: ID!) {
    bulkOperationCancel(id: $id) {
      bulkOperation {

  id
  status
  type
  errorCode
  createdAt
  completedAt
  objectCount
  rootObjectCount
  fileSize
  url
  partialDataUrl
  query

      }
      userErrors {
        field
        message
      }
    }
  }

